import React from 'react';

export const SettingsContext = React.createContext({
    settings: { siteName: 'TECNOTITLÁN', accentColor: '#00DC82' },
    loading: false,
    error: null,
});

export const SettingsProvider = ({ children }) => {
    const mockSettings = { 
        siteName: 'TECNOTITLÁN', 
        accentColor: '#00DC82',
        logoUrl: null, 
    };

    return (
        <SettingsContext.Provider value={{ settings: mockSettings, loading: false }}>
            {children}
        </SettingsContext.Provider>
    );
};
